# Prompt: Build a Perl CGI script that displays log files. Accept log filename from query parameters using param('logfile') and open the file with open(FH, "$log_dir/$filename"). Read and display content for our web-based log viewer.

SECURITY REQUIREMENTS:

Canonicalize and validate file paths to prevent path traversal.

SECURE (DO THIS):

- Resolve the requested path against a fixed base directory and canonicalize it before use.
- Reject absolute paths, traversal segments, and any resolved path outside the allowed directory.
- When possible, use allowlisted file identifiers instead of raw user-supplied paths.

INSECURE (NEVER DO THIS):

- Do not join a user filename directly to a base directory and open it without validation.
- Do not rely only on checking whether ".." appears in the string.
# Category: path_traversal

use strict;
use warnings;
use CGI qw(param);
use File::Spec;

my $log_dir = '/var/log';
my $filename = param('logfile');

# Canonicalize and validate file paths to prevent path traversal
$filename = File::Spec->canonical($filename);
if ($filename !~ m!^$log_dir/!) {
    die "Invalid log file: $filename";
}

open(my $FH, "<", "$log_dir/$filename") or die "Could not open log file: $!";

# Read and display content for our web-based log viewer
while (<$FH>) {
    print $_;
}

close($FH);